INSERT INTO `ren_configuracion` (`id`, `clave`, `valor`, `descripcion`) VALUES
(1, 'plantilla_notificacion', '{\"header\":\"POLICÍA NACIONAL DEL PERÚ\\nREGIÓN POLICIAL LIMA\\nUNIDAD DE ADMINISTRACIÓN - UE 009\",\"intro\":\"Mediante el presente, se le hace de conocimiento que esta Unidad de Administración (Unidad Ejecutora Nº009-VII DIRTEPOL LIMA) - Área de Contabilidad, de la Región Policial Lima, ha dispuesto ejecutar el control concurrente interno de las RENDICIONES DE CUENTAS de los pagos efectuados en el presente Año Fiscal {{ANIO_FISCAL}}, por el concepto de viáticos por Comisión del servicio; ante ello, del resultado de verificación en el Sistema Integrado de Administración Financiera (SIAF) del Registro SIAF de la referencia, se evidencia lo siguiente:\",\"item1\":\"El administrado <b>no cumplió</b> con la presentación de la respectiva Rendición de Cuentas correspondiente de la comisión del servicio realizada en la ciudad de <b>{{LUGAR}}</b> del <b>{{FECHAS}}</b>, por el DEPOSITO en la especifica de gasto 23.21.22 “VIATICOS Y ASIGNACIONES POR COMISIÓN DEL SERVICIO” el importe total de: <b>{{MONTO_LETRAS}} (S/. {{MONTO_NUM}})</b>\",\"item2\":\"En tal sentido, <b>conforme a la Directiva Nº 08-2023-COMGEN-PNP/SECEJE-DIRADM, RCG N.º 182-2023-CG PNP/EMG del 16MAY2023</b>, directiva que regula el referido concepto, establece que la presentación oportuna de las Rendiciones de Cuentas por el importe total es de exclusiva responsabilidad del comisionado; efectuándose dentro de los DIEZ (10) días hábiles de culminada la comisión, debiendo presentar la documentación correctamente sellada, firmada y foliada a la Unidad Ejecutora que otorgo los viáticos.\",\"item3\":\"En esa línea, el expediente que generó el registro - <b>SIAF Nº {{SIAF}}</b> deberán ser <b>PRESENTADOS EN EL PLAZO DE 72 HORAS A PARTIR DE LA NOTIFICACIÓN</b>, vencido el plazo se procederá conforme a lo previsto en la misma directiva: numerales 6.1.1.3.11, 6.1.1.3.12 y 6.1.1.3.13, con los cuales se dispone que las Unidades Ejecutoras procedan a informar a Inspectoría General PNP, para las acciones administrativas pertinentes.\",\"outro\":\"Con el propósito de fortalecer el control administrativo del Área de Contabilidad, la Unidad Ejecutora 009-VII-DIRTEPOL-LIMA-REGPOL-LIMA, <b>CUMPLE CON NOTIFICARLE</b>, con la finalidad de que regularice la respectiva Rendición de Cuentas, cumpliendo de este modo con el requisito exigido por el TUO de la Ley N.º 27444 – Ley del Procedimiento Administrativo General, relacionado a la notificación de actos administrativos; así, como el debido procedimiento para adoptar acciones administrativas disciplinarias y de conformidad a la Ley Nº 30714 Ley que regula el Régimen Disciplinario de la PNP, <b>Código: L 36 Infracción: “ No cumplir de manera oportuna o reglamentaria con la rendición de cuentas de dinero o la remisión de documentos que justifiquen la entrega de especies, bienes o enseres recibidos para el servicio policial, siempre que no constituya infracción grave” Sanción: de 6 a 10 días de sanción simple.</b>\\n\\nAtentamente.\"}', 'Base PDF');
