DELIMITER $$
--
-- Procedimientos
--
CREATE DEFINER=`sistemag`@`localhost` PROCEDURE `sp_generar_correlativo` (IN `p_anio` INT, IN `p_tipo` VARCHAR(50), OUT `p_nuevo_numero` INT)   BEGIN
    DECLARE max_num INT;
    
    -- Bloqueamos lectura para asegurar consistencia (opcional según motor, aquí usamos lógica simple)
    -- En InnoDB con transacción es seguro.
    
    SELECT MAX(numero) INTO max_num 
    FROM gestion_documental 
    WHERE anio = p_anio AND tipo = p_tipo;
    
    IF max_num IS NULL THEN
        SET p_nuevo_numero = 1;
    ELSE
        SET p_nuevo_numero = max_num + 1;
    END IF;
END$$

