--
-- Estructura para la vista `personal`
--
DROP TABLE IF EXISTS `personal`;

CREATE ALGORITHM=UNDEFINED DEFINER=`sistemag`@`localhost` SQL SECURITY DEFINER VIEW `personal`  AS SELECT `mae_personal`.`id_personal` AS `id_personal`, `mae_personal`.`id_grado` AS `id_grado`, `mae_personal`.`cip` AS `cip`, `mae_personal`.`situacion_cip` AS `situacion_cip`, `mae_personal`.`dni` AS `dni`, `mae_personal`.`tipo_dni` AS `tipo_dni`, `mae_personal`.`apellidos` AS `apellidos`, `mae_personal`.`nombres` AS `nombres`, `mae_personal`.`sexo` AS `sexo`, `mae_personal`.`fecha_nacimiento` AS `fecha_nacimiento`, `mae_personal`.`id_subunidad` AS `id_subunidad`, `mae_personal`.`cargo` AS `cargo`, `mae_personal`.`funcion_horario` AS `funcion_horario`, `mae_personal`.`estado` AS `estado`, `mae_personal`.`situacion_especial` AS `situacion_especial`, `mae_personal`.`fecha_registro` AS `fecha_registro` FROM `mae_personal` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_destinos_completa`
--
DROP TABLE IF EXISTS `vista_destinos_completa`;

CREATE ALGORITHM=UNDEFINED DEFINER=`sistemag`@`localhost` SQL SECURITY DEFINER VIEW `vista_destinos_completa`  AS SELECT `d`.`id_destino` AS `id_destino`, `d`.`id_region` AS `id_region`, `d`.`id_division` AS `id_division`, `d`.`id_subunidad` AS `id_subunidad`, `d`.`nombre_destino` AS `nombre_destino`, `d`.`activo` AS `activo`, `d`.`orden` AS `orden`, `r`.`nombre_region` AS `nombre_region`, `dv`.`nombre_division` AS `nombre_division`, `s`.`nombre_subunidad` AS `nombre_matriz` FROM (((`mae_destinos` `d` left join `regiones_policiales` `r` on(`d`.`id_region` = `r`.`id_region`)) left join `divisiones_policiales` `dv` on(`d`.`id_division` = `dv`.`id_division`)) left join `sub_unidades_policiales` `s` on(`d`.`id_subunidad` = `s`.`id_subunidad`)) ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_estadisticas_divisiones`
--
DROP TABLE IF EXISTS `vista_estadisticas_divisiones`;

CREATE ALGORITHM=UNDEFINED DEFINER=`sistemag`@`localhost` SQL SECURITY DEFINER VIEW `vista_estadisticas_divisiones`  AS SELECT `d`.`id_division` AS `id_division`, `d`.`nombre_division` AS `nombre_division`, `r`.`nombre_region` AS `nombre_region`, count(`s`.`id_subunidad`) AS `total_subunidades`, sum(case when `s`.`tipo_unidad` = 'COMISARÍA' then 1 else 0 end) AS `total_comisarias`, sum(case when `s`.`tipo_unidad` = 'JEFATURA' then 1 else 0 end) AS `total_jefaturas`, sum(case when `s`.`estado` = 1 then 1 else 0 end) AS `subunidades_activas` FROM ((`divisiones_policiales` `d` join `regiones_policiales` `r` on(`d`.`id_region` = `r`.`id_region`)) left join `sub_unidades_policiales` `s` on(`d`.`id_division` = `s`.`id_division`)) WHERE `d`.`estado` = 1 GROUP BY `d`.`id_division`, `d`.`nombre_division`, `r`.`nombre_region` ORDER BY `r`.`nombre_region` ASC, `d`.`nombre_division` ASC ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_permisos_usuario`
--
DROP TABLE IF EXISTS `vista_permisos_usuario`;

CREATE ALGORITHM=UNDEFINED DEFINER=`sistemag`@`localhost` SQL SECURITY DEFINER VIEW `vista_permisos_usuario`  AS SELECT `upp`.`usuario_id` AS `id_usuario`, `m`.`id` AS `modulo_id`, `m`.`nombre` AS `modulo_nombre`, `m`.`slug` AS `modulo_slug`, `a`.`id` AS `accion_id`, `a`.`nombre` AS `accion_nombre`, `a`.`slug` AS `accion_slug`, `upp`.`permitido` AS `tiene_permiso` FROM ((`modulos` `m` join `acciones` `a`) join `usuario_permisos_personalizados` `upp` on(`m`.`id` = `upp`.`modulo_id` and `a`.`id` = `upp`.`accion_id`)) ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_unidades_completa`
--
DROP TABLE IF EXISTS `vista_unidades_completa`;

CREATE ALGORITHM=UNDEFINED DEFINER=`sistemag`@`localhost` SQL SECURITY DEFINER VIEW `vista_unidades_completa`  AS SELECT `s`.`id_subunidad` AS `id_subunidad`, `s`.`nombre_subunidad` AS `nombre_subunidad`, `s`.`tipo_unidad` AS `tipo_unidad`, `s`.`codigo_subunidad` AS `codigo_subunidad`, `s`.`direccion` AS `subunidad_direccion`, `s`.`telefono` AS `subunidad_telefono`, `s`.`responsable` AS `responsable`, `s`.`departamento` AS `departamento`, `s`.`provincia` AS `provincia`, `s`.`distrito` AS `distrito`, `d`.`id_division` AS `id_division`, `d`.`nombre_division` AS `nombre_division`, `d`.`codigo_division` AS `codigo_division`, `r`.`id_region` AS `id_region`, `r`.`nombre_region` AS `nombre_region`, `r`.`codigo_region` AS `codigo_region`, `s`.`estado` AS `estado` FROM ((`sub_unidades_policiales` `s` join `divisiones_policiales` `d` on(`s`.`id_division` = `d`.`id_division`)) join `regiones_policiales` `r` on(`d`.`id_region` = `r`.`id_region`)) WHERE `d`.`estado` = 1 AND `r`.`estado` = 1 ORDER BY `r`.`nombre_region` ASC, `d`.`nombre_division` ASC, `s`.`tipo_unidad` ASC, `s`.`nombre_subunidad` ASC ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vw_segmentacion_detalle`
--
DROP TABLE IF EXISTS `vw_segmentacion_detalle`;

CREATE ALGORITHM=UNDEFINED DEFINER=`sistemag`@`localhost` SQL SECURITY INVOKER VIEW `vw_segmentacion_detalle`  AS SELECT `s`.`anio` AS `anio`, `s`.`ref_pac` AS `ref_pac`, `s`.`objeto_contratacion` AS `objeto_contratacion`, `tp`.`nombre` AS `tipo_proceso`, `s`.`descripcion` AS `proc_descripcion`, `s`.`cuantia` AS `cuantia`, `i`.`descripcion_item` AS `descripcion_item`, `i`.`monto_item` AS `monto_item`, `s`.`porcentaje` AS `porcentaje`, `s`.`cuantia_categoria` AS `cuantia_categoria`, `s`.`riesgo_categoria` AS `riesgo_categoria`, `s`.`resultado_segmentacion` AS `resultado_segmentacion` FROM ((`segmentacion` `s` left join `segmentacion_items` `i` on(`i`.`segmentacion_id` = `s`.`id`)) left join `tipo_proceso` `tp` on(`tp`.`id` = `s`.`tipo_proceso_id`)) ORDER BY `s`.`anio` ASC, `s`.`ref_pac` ASC, `i`.`id` ASC ;

